SELECT pattern_name, creation_date
FROM design_patterns
WHERE entity_type = 'Yes';

SELECT pattern_id, COUNT(*) AS example_count
FROM examples
GROUP BY pattern_id;

SELECT COUNT(*) 
FROM design_patterns 
WHERE pattern_name = 'Tuple';

SELECT entity_type, COUNT(*) AS pattern_count
FROM design_patterns
GROUP BY entity_type;

SELECT pattern_name, description, creation_date
FROM design_patterns
WHERE pattern_id = 0;
